import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './WeatherDashboard.css';

function WeatherDashboard() {
  const [weather, setWeather] = useState(null);
  const [city, setCity] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [history, setHistory] = useState([]);
  const [favorites, setFavorites] = useState([]);
  const [userId] = useState('user-' + Math.random().toString(36).substr(2, 9));
  const [activeTab, setActiveTab] = useState('search');
  const [suggestions, setSuggestions] = useState([]);

  const API_URL = 'http://localhost:5000';

  // Popular cities for autocomplete
  const POPULAR_CITIES = [
    'Karachi', 'Lahore', 'Islamabad', 'Peshawar', 'Quetta',
    'New York', 'London', 'Paris', 'Tokyo', 'Dubai',
    'Sydney', 'Singapore', 'Bangkok', 'Mumbai', 'Delhi',
    'Berlin', 'Rome', 'Madrid', 'Amsterdam', 'Toronto',
    'Los Angeles', 'Chicago', 'Houston', 'Phoenix', 'Philadelphia',
    'San Francisco', 'Seattle', 'Boston', 'Miami', 'Atlanta'
  ];

  // Handle input change for suggestions
  const handleInputChange = (e) => {
    const value = e.target.value;
    setCity(value);

    if (value.length > 0) {
      const filtered = POPULAR_CITIES.filter(c =>
        c.toLowerCase().includes(value.toLowerCase())
      );
      setSuggestions(filtered);
    } else {
      setSuggestions([]);
    }
  };

  // Handle suggestion click
  const handleSuggestionClick = (suggestionCity) => {
    setCity(suggestionCity);
    setSuggestions([]);
    fetchWeather(suggestionCity);
  };

  // Fetch Weather
  const fetchWeather = async (cityName) => {
    setLoading(true);
    setError('');
    setSuggestions([]);
    try {
      const response = await axios.get(`${API_URL}/api/weather`, {
        params: { city: cityName, userId },
      });
      setWeather(response.data);
      fetchHistory();
    } catch (err) {
      setError('❌ City not found. Please try again.');
      setWeather(null);
    }
    setLoading(false);
  };

  // Fetch History
  const fetchHistory = async () => {
    try {
      const response = await axios.get(`${API_URL}/api/history`, {
        params: { userId },
      });
      setHistory(response.data);
    } catch (err) {
      console.error('Error fetching history:', err);
    }
  };

  // Fetch Favorites
  const fetchFavorites = async () => {
    try {
      const response = await axios.get(`${API_URL}/api/favorites`, {
        params: { userId },
      });
      setFavorites(response.data);
    } catch (err) {
      console.error('Error fetching favorites:', err);
    }
  };

  // Load on mount
  useEffect(() => {
    fetchHistory();
    fetchFavorites();
  }, [userId, API_URL]);

  // Handle Search
  const handleSearch = () => {
    if (city.trim()) {
      fetchWeather(city);
      setCity('');
    }
  };

  // Add to Favorites
  const addToFavorites = async () => {
    if (!weather) return;
    try {
      await axios.post(`${API_URL}/api/favorites`, {
        userId,
        city: weather.city,
      });
      fetchFavorites();
      alert('✅ Added to favorites!');
    } catch (err) {
      alert('⚠️ Already in favorites!');
    }
  };

  // Remove from Favorites
  const removeFromFavorites = async (id) => {
    try {
      await axios.delete(`${API_URL}/api/favorites/${id}`);
      fetchFavorites();
    } catch (err) {
      console.error('Error:', err);
    }
  };

  // Get Background Class
  const getBackgroundClass = () => {
    if (!weather) return 'bg-initial';
    const condition = weather.condition.toLowerCase();
    if (condition.includes('sunny') || condition.includes('clear')) return 'bg-sunny';
    if (condition.includes('rain')) return 'bg-rainy';
    if (condition.includes('cloud')) return 'bg-cloudy';
    if (condition.includes('snow')) return 'bg-snowy';
    if (condition.includes('thunder')) return 'bg-storm';
    return 'bg-default';
  };

  return (
    <div className={`dashboard ${getBackgroundClass()}`}>
      <div className="animated-background">
        <div className="blob blob-1"></div>
        <div className="blob blob-2"></div>
        <div className="blob blob-3"></div>
      </div>

      <div className="overlay"></div>

      <div className="container">
        {/* Initial Welcome Screen */}
        {!weather && (
          <div className="welcome-section">
            <div className="welcome-content">
              <div className="title-icon">🌍</div>
              <h1 className="welcome-title">Weather Dashboard</h1>
              <p className="welcome-subtitle">
                Discover real-time weather information from around the world
              </p>
            </div>
          </div>
        )}

        {/* Search Box */}
        <div className="search-container">
          <div className="search-box">
            <input
              type="text"
              placeholder="Search for a city..."
              value={city}
              onChange={handleInputChange}
              onKeyPress={(e) => e.key === 'Enter' && handleSearch()}
              className="search-input"
              autoComplete="off"
            />
            <button onClick={handleSearch} disabled={loading} className="search-btn">
              {loading ? '⏳' : '🔍'}
            </button>

            {/* Suggestions Dropdown */}
            {suggestions.length > 0 && (
              <div className="suggestions">
                {suggestions.map((sug, index) => (
                  <div
                    key={index}
                    className="suggestion-item"
                    onClick={() => handleSuggestionClick(sug)}
                  >
                    📍 {sug}
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Error */}
        {error && (
          <div className="error-message">
            <span className="error-icon">⚠️</span>
            {error}
          </div>
        )}

        {/* Weather Card */}
        {weather && (
          <div className="weather-card">
            <div className="weather-header">
              <div className="city-info">
                <h2>{weather.city}, {weather.country}</h2>
                <p className="date-time">
                  {new Date().toLocaleDateString('en-US', {
                    weekday: 'long',
                    year: 'numeric',
                    month: 'long',
                    day: 'numeric'
                  })}
                </p>
              </div>
              <button className="favorite-btn" onClick={addToFavorites}>
                ❤️
              </button>
            </div>

            <div className="weather-main">
              <div className="temperature-section">
                <div className="weather-icon">
                  {weather.condition.includes('Cloud') && '☁️'}
                  {weather.condition.includes('Rain') && '🌧️'}
                  {weather.condition.includes('Clear') && '☀️'}
                  {weather.condition.includes('Snow') && '❄️'}
                  {weather.condition.includes('Thunder') && '⛈️'}
                  {weather.condition.includes('Sunny') && '🌞'}
                  {!['Cloud', 'Rain', 'Clear', 'Snow', 'Thunder', 'Sunny'].some(c => weather.condition.includes(c)) && '🌤️'}
                </div>
                <div className="temperature-info">
                  <div className="temperature">{weather.temperature}°</div>
                  <div className="condition">{weather.condition}</div>
                  <div className="description">{weather.description}</div>
                </div>
              </div>

              <div className="feels-like-box">
                <span className="label">Feels like</span>
                <span className="value">{weather.feelsLike}°C</span>
              </div>
            </div>

            <div className="details">
              <div className="detail-item">
                <div className="detail-icon">💧</div>
                <div className="detail-content">
                  <span className="detail-label">Humidity</span>
                  <span className="detail-value">{weather.humidity}%</span>
                </div>
              </div>
              <div className="detail-item">
                <div className="detail-icon">💨</div>
                <div className="detail-content">
                  <span className="detail-label">Wind Speed</span>
                  <span className="detail-value">{weather.windSpeed} km/h</span>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Tabs */}
        {weather && (
          <>
            <div className="tabs">
              <button
                className={`tab ${activeTab === 'search' ? 'active' : ''}`}
                onClick={() => setActiveTab('search')}
              >
                🔍 Search
              </button>
              <button
                className={`tab ${activeTab === 'history' ? 'active' : ''}`}
                onClick={() => {
                  setActiveTab('history');
                  fetchHistory();
                }}
              >
                📜 History ({history.length}/10)
              </button>
              <button
                className={`tab ${activeTab === 'favorites' ? 'active' : ''}`}
                onClick={() => {
                  setActiveTab('favorites');
                  fetchFavorites();
                }}
              >
                ❤️ Favorites ({favorites.length})
              </button>
            </div>

            {/* History Tab */}
            {activeTab === 'history' && (
              <div className="tab-content">
                <h3>📜 Search History</h3>
                {history.length === 0 ? (
                  <p className="empty-message">No search history yet</p>
                ) : (
                  <div className="list">
                    {history.map((item, index) => (
                      <div key={index} className="list-item">
                        <div className="list-content">
                          <strong>{item.city}</strong>
                          <p>{item.temperature}°C • {item.condition}</p>
                          <small>{new Date(item.timestamp).toLocaleString()}</small>
                        </div>
                        <button
                          onClick={() => fetchWeather(item.city)}
                          className="btn-small"
                        >
                          View
                        </button>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {/* Favorites Tab */}
            {activeTab === 'favorites' && (
              <div className="tab-content">
                <h3>❤️ Favorite Cities</h3>
                {favorites.length === 0 ? (
                  <p className="empty-message">No favorites yet</p>
                ) : (
                  <div className="list">
                    {favorites.map((fav) => (
                      <div key={fav._id} className="list-item">
                        <div className="list-content">
                          <strong>{fav.city}</strong>
                          <small>Added {new Date(fav.addedAt).toLocaleDateString()}</small>
                        </div>
                        <div className="button-group">
                          <button
                            onClick={() => fetchWeather(fav.city)}
                            className="btn-small btn-view"
                          >
                            View
                          </button>
                          <button
                            onClick={() => removeFromFavorites(fav._id)}
                            className="btn-small btn-delete"
                          >
                            Delete
                          </button>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

export default WeatherDashboard;
